mapper.select:
SELECT * FROM email_notification_task
WHERE status = 'PENDING'
  AND scheduled_at <= #{now}
ORDER BY scheduled_at ASC, id ASC
LIMIT #{limit}

mapper.update:
UPDATE email_notification_task
SET status = #{toStatus},
    update_time = CURRENT_TIMESTAMP(3)
WHERE id = #{id}
  AND status = #{fromStatus}

mapper.select:
SELECT COUNT(1)
FROM email_notification_task
WHERE receiver_uid = #{receiverUid}
  AND template_code = #{templateCode}
  AND biz_type = #{bizType}
  AND biz_id = #{bizId}
  AND status = 'SENT'
  AND sent_at >= #{since}

SELECT * FROM email_notification_task

ORDER BY id DESC
LIMIT #{size} OFFSET #{offset}
